// Final corrections: Monday-Sunday schedule, profile scroll reset, visible assigned names.
(function(){
  function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]})}
  function monday(d){d=new Date(d||new Date());var off=(d.getDay()+6)%7;d.setHours(0,0,0,0);d.setDate(d.getDate()-off);return d}
  function addDays(d,n){d=new Date(d);d.setDate(d.getDate()+n);return d}
  function iso(d){return d.toISOString().slice(0,10)}
  function dates(){var base=monday(typeof weekStart!=='undefined'?weekStart:new Date());if(typeof weekStart!=='undefined')weekStart=base;return [0,1,2,3,4,5,6].map(function(n){return iso(addDays(base,n))})}
  function dayLabel(d){var a=new Date(d+'T12:00:00');return a.toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short'})}
  function rangeLabel(a,b){var x=new Date(a+'T12:00:00'),y=new Date(b+'T12:00:00');return x.toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})+' - '+y.toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
  function userName(id){if(!id||id==='unassigned')return 'Unassigned';var u=(state.users||[]).find(function(x){return x.id===id});return u?(u.nickname||u.name||u.firstName||'User'):'Unassigned'}
  function published(s,firstDay){return !!s.publishedAt || (state.publishedWeeks&&state.publishedWeeks[firstDay]&&state.publishedWeeks[firstDay].shiftIds||[]).includes(s.id)}
  function card(s,firstDay){var cls=s.userId==='unassigned'?'unassigned':published(s,firstDay)?'published':'planned';return '<div class="shiftCard compactShift '+cls+'" onclick="openShiftModal(\''+s.id+'\')"><span class="compactName">'+esc(userName(s.userId))+'</span><span class="compactTime">'+esc(s.start)+'-'+esc(s.end)+'</span>'+(s.notes?'<small>'+esc(s.notes)+'</small>':'')+'</div>'}
  function tools(){if(typeof can==='function'&&!can('manageRota'))return '';var t=state.rotaTemplates||[];return '<div class="scheduleAdminTools"><h2>Rota planning</h2><div class="planningActions scheduleActions"><button onclick="copyCurrentWeek()">Copy current week</button><button class="secondary" onclick="pasteCopiedWeek()">Paste copied week here</button><button class="secondary" onclick="saveCurrentWeekAsTemplate()">Save week as template</button><button onclick="openSaveRotaModal()">Save rota</button></div>'+(t.length?'<div class="templateLoadRow"><label>Load template<select id="scheduleTemplateSelect">'+t.map(function(x){return '<option value="'+x.id+'">'+esc(x.name)+'</option>'}).join('')+'</select></label><button class="secondary" onclick="loadTemplateToCurrentWeek(document.getElementById(\'scheduleTemplateSelect\').value)">Load template</button></div>':'')+'</div>'}
  window.renderRota=function(){var ds=dates(),first=ds[0],last=ds[6],sections=state.sections||[];var html='<div class="toolbar scheduleToolbarFinal"><button class="secondary" aria-label="Previous week" onclick="weekStart=addDays(weekStart,-7);renderRota()">‹</button><strong>'+rangeLabel(first,last)+'</strong><button class="secondary" aria-label="Next week" onclick="weekStart=addDays(weekStart,7);renderRota()">›</button></div><div id="rotaGrid" class="bandedRota"><div class="bandDayHeader">'+ds.map(function(d){var p=dayLabel(d).split(' ');return '<div class="bandDayHead"><strong>'+p[0]+'</strong><span>'+p.slice(1).join(' ')+'</span></div>'}).join('')+'</div>'+sections.map(function(sec){return '<section class="rotaSectionBand"><div class="sectionBandTitle">'+esc(sec)+'</div><div class="bandWeekGrid">'+ds.map(function(d){var shifts=(state.shifts||[]).filter(function(s){return s.section===sec&&s.date===d}).sort(function(a,b){return String(a.start).localeCompare(String(b.start))});return '<div class="bandDayCell compactDayCell">'+(shifts.length?shifts.map(function(s){return card(s,first)}).join(''):'<span class="muted emptyCell">—</span>')+((typeof can!=='function'||can('manageRota'))?'<button class="cellAddShift" onclick="openShiftModal(\'\',\''+d+'\',\''+esc(sec)+'\')">+</button>':'')+'</div>'}).join('')+'</div></section>'}).join('')+'</div><p class="muted swipeHint">Monday-Sunday rota. Swipe left or right to change week.</p>'+tools();shell(html);var grid=document.getElementById('rotaGrid');if(grid){grid.addEventListener('touchstart',function(e){window.__rotaSwipeX=e.touches[0].clientX},{passive:true});grid.addEventListener('touchend',function(e){var dx=e.changedTouches[0].clientX-(window.__rotaSwipeX||0);if(Math.abs(dx)>45){weekStart=addDays(weekStart,dx<0?7:-7);renderRota()}},{passive:true});}window.scrollTo(0,0)};
  var oldOpen=window.openProfile;
  if(oldOpen){window.openProfile=function(id){oldOpen(id);setTimeout(function(){window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;},0);setTimeout(function(){window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;},80)}}
  var oldEdit=window.openProfileEdit;
  if(oldEdit){window.openProfileEdit=function(id){oldEdit(id);setTimeout(function(){window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;},0);setTimeout(function(){window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;},80)}}
  window.monday=monday;window.addDays=addDays;
})();
